import React, { useState, Suspense} from 'react';
import './index.css';
import Header from "./Debugger_Components/Layouts/Header.js";
import { TextEncoderStream, TextDecoderStream } from "@stardazed/streams-text-encoding";

function App(props){
  const [board, setBoard] = useState("BBCMicrobit");
  const [port, setPort] = useState("");
  const [writer, setWriter] = useState(null);
  const [reader, setReader] = useState(null);
  const [writableStreamClosed , setWritableStreamClosed] = useState(null);
  /****************************************************
   *  Using the Google Serial Api, this method will open a port request window in the Chrome Browser and allow the user to select a Serial Device connected to their computer.
   *  This method is the main point for updating/setting the port state, serial writer, and serial reader.
   * 
   */
  
  async function connect(){
    if ('serial' in navigator) {
      try {
          const port = await navigator.serial.requestPort();
          await port.open({ baudRate: 115200 });//This needs to be baudrate, lower case, on my machine which uses an older version of the Serial API
          setReader(port.readable.getReader());

          const textEncoder = new TextEncoderStream();
          setWritableStreamClosed(textEncoder.readable.pipeTo(port.writable));
          setWriter(textEncoder.writable.getWriter());
          setPort(port);     
          let signals = await port.getSignals();
          console.log(signals);
      }
      catch (err) {
          console.error('There was an error opening the serial port:', err);
      }
    }
    else {
        console.error('Web serial doesn\'t seem to be enabled in your browser. Try enabling it by visiting:');
        console.error('chrome://flags/#enable-experimental-web-platform-features');
        console.error('opera://flags/#enable-experimental-web-platform-features');
        console.error('edge://flags/#enable-experimental-web-platform-features');
    }
  } /* End connect() */

  /**
   * This method will clean up a Serial Port connection by closing the writer, reader, and port connection. This is necessary if a student needs to switch
   * from the Live Debugger to a different IDE and have the second IDE connect to the Serial Device. 
   */
  async function disconnect(){
    try{
      if(port !== "" && writer !== null)
      {
        writer.close();
        await writableStreamClosed;
        await reader.cancel();
        await port.close();
        setPort("");
        setWriter(null);
        setReader(null);
      }
    }
    catch(e)
    {
      console.log("Unable to disconnect. Resetting connection variables to null");
      setPort("");
      setWriter(null);
      setReader(null);
    }
  }/* End disconnect() */

  async function updateReader()
  {
    if(port)
    {
       try{
          reader.releaseLock();
          let newReader = port.readable.getReader();
          setReader( newReader);
          
       }catch(e)
       {
         console.log("Error updating reader.");
         console.log(e);
       }
    }
    else{
      console.log("Cannot create a new reader. Port has not been set");
    }
  }

  let controller = "";

  if(board !== null)
  {
    const Component =  React.lazy(() => import('./Debugger_Components/Boards/' + board + "/Controller.js"));
    controller = <Component reader={reader} writer={writer} disconnect={disconnect} updateReader={updateReader}/>
  }

  //Verify the device hasn't been disconnected
  if(port !== "" && writer !== null)
  {
        writer.write("").catch(() =>{
        setPort("");
        setWriter(null);
        setReader(null);
        setWritableStreamClosed(null);
        console.log("Error accessing device, port forceably closed and must be reconnnected.");
      }
    );
  }

  return(
    <>
      <Header connect={connect} disconnect={disconnect} connectionStatus={eval(port !== "")} boardStatus ={eval(board !== null)} selectBoard={setBoard}/>
      <Suspense fallback={<p class="h1">Loading...</p>}>
        {controller}
      </Suspense>
    </>
  );
}

export default App;