import React, { useState} from 'react';
import ColorTheme from "./ColorTheme.js";
import {boards} from "../Boards/BoardList.js"
import Modal from 'react-bootstrap/Modal';
import Button from 'react-bootstrap/Button'
//import 'bootstrap';
/**
 * The Header component contains utilities for connecting the Live Debugger to a Serial Monitor and displaying instructions to the user.
 * This method accepts two methods (connect, disconnect) which handle calls to the Chrome Serial API for opening/closing port connections,
 * and a third boolean parameter which determines if a port connection has been successfully established
 * ```js
    <Header connect={connect} disconnect={disconnect} connectionStatus={eval(port !== "")}/>
    ```
 */

function Header({connect, disconnect, connectionStatus, boardStatus, selectBoard}) {
    const [showInstructions, setShowInstructions] = useState(false);

    let height = 70;

    let connectButton = <button type="button" className="btn color1 btn-block" style={{height:"100%", fontWeight:"bold",fontSize:"1.25em"}} onClick={() => {connect()}} disabled={!boardStatus}> Connect </button> ;
    
    if(connectionStatus)
    {
        connectButton = <button type="button" className="btn color1 btn-block" style={{ height:"100%", fontWeight:"bold", fontSize:"1.25em"}} onClick={() => {disconnect()}} > Disconnect </button> ;
    }

    let boardSelection = boards.map((board) => <a class="dropdown-item" style={{cursor:"pointer"}} onClick={() =>{selectBoard(board.folder)}}>{board.name}</a>);
    return (
        <>
            <div className="container-fluid p-0" style={{fontWeight:"bold"}}>
                <div className="row no-gutters color1" style={{ borderTop:"solid 3px var(--fontColor1)"}}>
                    <div className="col-12 col-md-2 pt-3" style={{height: height, borderRight:"solid 3px var(--fontColor1)"}} >
                        <div class="row justify-content-center no-gutters">
                            <div class="col-6 mr-1">
                                <div class="btn-group w-100" role="group" aria-label="Select Board Type"  style={{height:"100%"}} >
                                    <button class="btn color1 dropdown-toggle" style={{ fontWeight:"bold",fontSize:"1.25em"}} type="button" id="portBoard" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false">
                                        Select Board
                                    </button>
                                    <div class="dropdown-menu" id="portBoard_group" aria-labelledby="portBoard">
                                        {boardSelection}
                                    </div>
                                </div>
                            </div>
                            <div class="col-5">
                                {connectButton}
                            </div>
                        </div>
                    </div>
                    <div className="col-12 col-md-8 pt-3 justify-content-center" style={{height: height, borderRight:"solid 3px var(--fontColor1)"}}>
                        <div class="row justify-content-center no-gutters">
                            <div class="col-8">
                                <a type="button" className="btn color1 btn-block" style={{ height:"100%", fontWeight:"bold", fontSize:"1.25em"}} target="_blank" href="https://www.instructables.com/Circuit-Check-a-Hardware-Debugger-and-Tester-for-A/" > Setup and Instructions </a>
                            </div>
                        </div>
                    </div>
                    <div className="col-12 col-md-2 pt-3" style={{height: height}} >
                        <div class="row justify-content-center no-gutters">
                            <div class="col-8">
                                <ColorTheme width="100%" />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            {/* Old instructions onclick - () => {setShowInstructions(true); */}
            <Modal show={showInstructions} onHide={() => setShowInstructions(false)} size="lg" centered >
                <Modal.Header closeButton>
                    <Modal.Title>Instructions</Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    <div class="container">
                        <div class="row">
                            <div class="col"></div>
                            <div class="col"><iframe src="https://drive.google.com/file/d/1AYN5ViY9jHlqMgOfKb-z-Sznr3wAECxk/preview" width="640" height="360"></iframe></div>
                            <div class="col"></div>
                        </div>
                    </div>
                    
                    <p>Instructional Video</p>
                </Modal.Body>
                <Modal.Footer>
                    <Button variant="secondary" onClick={() => setShowInstructions(false)}>
                        Close
                    </Button>
                </Modal.Footer>
            </Modal>
        </>
    );
}
  
export default Header